        if !AnalyticsDebugConfig.shared.includePII {
            out = redactLikelyPII(in: out)
        }
        return out
    }

    private func redactLikelyTokens(in s: String) -> String {
        var out = s
        let patterns = [
            #"(?i)\b(bearer)\s+([A-Za-z0-9\-\._~\+\/]+=*)"#,
            #"(?i)\b(access[_-]?token|refresh[_-]?token|id[_-]?token|token)\b"\s*:\s*"([^"]+)""#,
            #"(?i)\b(access[_-]?token|refresh[_-]?token|id[_-]?token|token)\b"\s*=\s*([^\s&]+)"#,
            #"\beyJ[A-Za-z0-9_\-]+\.[A-Za-z0-9_\-]+\.[A-Za-z0-9_\-]+\b"#
        ]
        for p in patterns {
            out = out.replacingOccurrences(of: p, with: AnalyticsDebugConfig.shared.redactReplacement, options: .regularExpression)
        }
        return out
    }

    private func redactLikelyPII(in s: String) -> String {
        var out = s
        let patterns = [
            #"[A-Z0-9a-z._%+-]+@[A-Za-z0-9.-]+\.[A-Za-z]{2,}"#,
            #"(?i)\b(email|user[_-]?id|userid|phone|address|name)\b"\s*:\s*"([^"]+)""#,
            #"(?i)\b(email|user[_-]?id|userid|phone|address|name)\b"\s*=\s*([^\s&]+)"#
        ]
        for p in patterns {
            out = out.replacingOccurrences(of: p, with: AnalyticsDebugConfig.shared.redactReplacement, options: .regularExpression)
        }
        return out
    }

    private func serialize(_ payload: [String: Any]) -> String {
        if JSONSerialization.isValidJSONObject(payload),
           let data = try? JSONSerialization.data(withJSONObject: payload, options: [.sortedKeys]),
           let s = String(data: data, encoding: .utf8) {
            return s
        }
        return String(describing: payload)
    }

    private func installAppLifecycleHooks() {
        NotificationCenter.default.addObserver(forName: UIApplication.didFinishLaunchingNotification, object: nil, queue: nil) { [weak self] _ in
            self?.log(.info, event: "app_launch", message: "App did finish launching", metadata: [:])
        }
        NotificationCenter.default.addObserver(forName: UIApplication.willEnterForegroundNotification, object: nil, queue: nil) { [weak self] _ in
            self?.log(.info, event: "app_foreground", message: "App will enter foreground", metadata: [:])
        }
        NotificationCenter.default.addObserver(forName: UIApplication.didEnterBackgroundNotification, object: nil, queue: nil) { [weak self] _ in
            self?.log(.info, event: "app_background", message: "App did enter background", metadata: [:])
        }
        NotificationCenter.default.addObserver(forName: UIApplication.willTerminateNotification, object: nil, queue: nil) { [weak self] _ in
            self?.log(.warning, event: "app_terminate", message: "App will terminate", metadata: [:])
        }
    }

    private func installUncaughtExceptionHandler() {
        NSSetUncaughtExceptionHandler { exception in
            let md: [String: Any?] = [
                "name": exception.name.rawValue,
                "reason": exception.reason,
                "user_info": exception.userInfo,
                "call_stack": exception.callStackSymbols
            ]
            AnalyticsDebugLogger.shared.log(.error, event: "uncaught_exception", message: "Uncaught exception", metadata: md)
        }
    }

    private func installSignalHandlers() {
        let signals: [Int32] = [SIGABRT, SIGILL, SIGSEGV, SIGFPE, SIGBUS, SIGPIPE]
        for sig in signals {
            signal(sig) { sig in
                AnalyticsDebugLogger.shared.log(.error, event: "signal", message: "Received signal \(sig)", metadata: ["signal": sig])
                fflush(stderr)
                _exit(sig)
            }
        }
    }
