public final class AnalyticsDebugURLSessionDelegate: NSObject, URLSessionTaskDelegate, URLSessionDataDelegate {
    private struct TaskState {
        var requestID: String
        var start: CFAbsoluteTime
        var receivedData: Data
    }

    private let lock = NSLock()
    private var states: [Int: TaskState] = [:]

    public var userIDProvider: (() -> String?)?
    public var emailProvider: (() -> String?)?
    public var tokenProvider: (() -> String?)?

    public override init() {
        super.init()
    }

    public func urlSession(_ session: URLSession, task: URLSessionTask, didCompleteWithError error: Error?) {
        let taskID = task.taskIdentifier
        lock.lock()
        let state = states.removeValue(forKey: taskID)
        lock.unlock()

        let durationMs: Double? = state.map { (CFAbsoluteTimeGetCurrent() - $0.start) * 1000.0 }

        if let error {
            AnalyticsDebugLogger.shared.apiError(
                requestID: state?.requestID ?? "unknown",
                method: task.originalRequest?.httpMethod,
                url: task.originalRequest?.url?.absoluteString,
                statusCode: (task.response as? HTTPURLResponse)?.statusCode,
                headers: (task.response as? HTTPURLResponse)?.allHeaderFields as? [String: String],
                body: state?.receivedData.flatMap { String(data: $0, encoding: .utf8) },
                error: error,
                durationMs: durationMs
            )
            return
        }

        if let http = task.response as? HTTPURLResponse {
            let body: Any? = state?.receivedData.flatMap { String(data: $0, encoding: .utf8) }
            AnalyticsDebugLogger.shared.apiResponse(
                requestID: state?.requestID ?? "unknown",
                statusCode: http.statusCode,
                headers: http.allHeaderFields as? [String: String],
                body: body,
                durationMs: durationMs
            )
        } else {
            AnalyticsDebugLogger.shared.log(.warning, event: "api_response_non_http", message: "Non-HTTP response", metadata: [
                "request_id": state?.requestID ?? "unknown",
                "duration_ms": durationMs as Any
            ])
        }
    }

    public func urlSession(_ session: URLSession, dataTask: URLSessionDataTask, didReceive data: Data) {
        let taskID = dataTask.taskIdentifier
        lock.lock()
        if var state = states[taskID] {
            state.receivedData.append(data)
            states[taskID] = state
        }
        lock.unlock()
    }

    public func urlSession(_ session: URLSession, task: URLSessionTask, didSendBodyData bytesSent: Int64, totalBytesSent: Int64, totalBytesExpectedToSend: Int64) {
        AnalyticsDebugLogger.shared.log(.verbose, event: "api_upload_progress", message: "Upload progress", metadata: [
            "task_id": task.taskIdentifier,
            "bytes_sent": bytesSent,
            "total_bytes_sent": totalBytesSent,
            "total_bytes_expected": totalBytesExpectedToSend
        ])
    }

    public func urlSession(_ session: URLSession, task: URLSessionTask, willBeginDelayedRequest request: URLRequest, completionHandler: @escaping (URLSession.DelayedRequestDisposition, URLRequest?) -> Void) {
        completionHandler(.continueLoading, nil)
    }

    public func urlSession(_ session: URLSession, task: URLSessionTask, willPerformHTTPRedirection response: HTTPURLResponse, newRequest request: URLRequest, completionHandler: @escaping (URLRequest?) -> Void) {
        AnalyticsDebugLogger.shared.log(.info, event: "api_redirect", message: "HTTP redirect", metadata: [
            "status_code": response.statusCode,
            "from": response.url?.absoluteString as Any,
            "to": request.url?.absoluteString as Any
        ])
        completionHandler(request)
    }

    public func track(_ request: URLRequest, task: URLSessionTask) {
        let requestID = UUID().uuidString
        let headers = request.allHTTPHeaderFields
        let query = request.url.flatMap { URLComponents(url: $0, resolvingAgainstBaseURL: false)?.queryItems }?.reduce(into: [String: Any?]()) { acc, item in
            acc[item.name] = item.value
        }
        let body: Any? = request.httpBody.flatMap { String(data: $0, encoding: .utf8) }

        AnalyticsDebugLogger.shared.apiRequest(
            id: requestID,
            method: request.httpMethod ?? "UNKNOWN",
            url: request.url?.absoluteString ?? "unknown",
            headers: headers,
            query: query,
            body: body,
            userID: userIDProvider?(),
            email: emailProvider?(),
            token: tokenProvider?()
        )

        lock.lock()
        states[task.taskIdentifier] = TaskState(requestID: requestID, start: CFAbsoluteTimeGetCurrent(), receivedData: Data())
        lock.unlock()
    }
}

public final class AnalyticsDebugURLSession {
    public static let shared = AnalyticsDebugURLSession()

    public let delegate = AnalyticsDebugURLSessionDelegate()
    public lazy var session: URLSession = {
        URLSession(configuration: .default, delegate: delegate, delegateQueue: nil)
    }()

    private init() {}

    public func dataTask(with request: URLRequest, completionHandler: @escaping (Data?, URLResponse?, Error?) -> Void) -> URLSessionDataTask {
        let task = session.dataTask(with: request, completionHandler: completionHandler)
        delegate.track(request, task: task)
        return task
    }

    public func dataTask(with url: URL, completionHandler: @escaping (Data?, URLResponse?, Error?) -> Void) -> URLSessionDataTask {
        let request = URLRequest(url: url)
        return dataTask(with: request, completionHandler: completionHandler)
    }
}

