public enum AnalyticsDebug {
    public static func configure(_ block: (inout AnalyticsDebugConfig) -> Void) {
        var cfg = AnalyticsDebugConfig.shared
        block(&cfg)
        AnalyticsDebugConfig.shared = cfg
        AnalyticsDebugLogger.shared.updateOSLogger()
    }

    public static func logger() -> AnalyticsDebugLogger { .shared }
    public static func urlSession() -> AnalyticsDebugURLSession { .shared }
    public static func interactions() -> AnalyticsDebugInteractionTracker { .shared }
}